// Clone or pull latest repo
const { execSync } = require('child_process');
const path = '/tmp/agent-studio';
execSync(`git clone https://ghp_TOKEN@github.com/nima54851/agent-studio.git ${path} 2>/dev/null || (cd ${path} && git pull)`, {stdio:'pipe'});
return [{json: {repoPath: path, status: 'cloned'}}];

const { execSync } = require('child_process');
const path = items[0].json.repoPath;
try {
  const out = execSync(`python3 ${path}/skills/openapi-automation/generate_openapi.py --app ${path}/src/app.js --output ${path}/openapi.yaml`, {timeout: 30000}).toString();
  return [{json: {success: true, output: out}}];
} catch(e) {
  return [{json: {success: false, error: e.message}}];
}

const { execSync } = require('child_process');
const path = items[0].json.repoPath;
try {
  const out = execSync(`python3 ${path}/skills/openapi-automation/validate_spec.py ${path}/openapi.yaml`).toString();
  return [{json: {validation: out}}];
} catch(e) {
  return [{json: {validation: e.stdout || e.message}}];
}

const { execSync } = require('child_process');
const path = items[0].json.repoPath;
try {
  execSync(`mkdir -p ${path}/docs && cp ${path}/openapi.yaml ${path}/docs/`, {stdio:'pipe'});
  return [{json: {docs: 'generated'}}];
} catch(e) {
  return [{json: {docs: e.message}}];
}

const { execSync } = require('child_process');
const path = items[0].json.repoPath;
const { YOUR_GITHUB_TOKEN } = process.env;
try {
  const token = '{{GITHUB_TOKEN}}';
  execSync(`cd ${path} && git config user.email 'agent-studio@bot' && git config user.name 'agent-studio bot' && git add openapi.yaml docs/ && git commit -m 'chore: auto-generated OpenAPI spec' && git push https://${token}@github.com/nima54851/agent-studio.git main`, {stdio:'pipe', timeout: 30000});
  return [{json: {pushed: true}}];
} catch(e) {
  return [{json: {pushed: false, error: e.message}}];
}
